code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge } from 'decantr/components';

code.example:
function PipelineCardsOutlined() {
  const { section, div, h2, p, span } = tags;
  const steps = [
    { num: 1, name: 'Intent', desc: 'User describes what they want to build.', color: '#F58882' },
    { num: 2, name: 'Interpret', desc: 'Parse intent into structured form.', color: '#FDA303' },
    { num: 3, name: 'Decompose', desc: 'Split into theme, structure, features.', color: '#0AF3EB' },
    { num: 4, name: 'Specify', desc: 'Write the machine-readable spec.', color: '#00E0AB' },
    { num: 5, name: 'Compose', desc: 'Resolve layouts from patterns.', color: '#FCD021' },
  ];

  return section({ class: css('_py30 _relative _z1') },
    div({ class: css('_container') },
      h2({ class: css('_heading2 _text[center] _mb4') }, 'The Pipeline'),
      p({ class: css('_text[center] _fgmuted _mx[auto] _mb14') }, 'How it works.'),
      div({ class: css('_grid _gc2 _gap6 _mw[920px] _mx[auto]') },
        steps.map(s =>
          Card({ class: css('_rounded[16px] _p7 _pt8 _relative _border[3px_solid] _bgtransparent _transition'), style: `border-color:${s.color}` },
            Badge({ class: css('_inline-flex _items[center] _justify[center] _w8 _h8 _rounded[50%] _mono _fs[0.8rem] _fw700 _mb3'), style: `background:${s.color};color:#0D0D1A` }, s.num),
            div({ class: css('_fs[1.15rem] _fw700 _mb2'), style: `color:${s.color}` }, s.name),
            p({ class: css('_fs[0.85rem] _lh[1.6] _fgwhite/75') }, s.desc)
          )
        )
      )
    )
  );
}

